package markets

import (
	"context"
	"time"

	positionsmath "socialpredict/internal/domain/math/positions"
	users "socialpredict/internal/domain/users"
	"socialpredict/models"
)

const (
	MaxQuestionTitleLength = 160
	MaxDescriptionLength   = 2000
	MaxLabelLength         = 20
	MinLabelLength         = 1
)

// Clock provides time functionality for testability.
type Clock interface {
	Now() time.Time
}

type serviceClock struct{}

func (serviceClock) Now() time.Time { return time.Now() }

// MarketReadRepository exposes market reads.
type MarketReadRepository interface {
	GetByID(ctx context.Context, id int64) (*Market, error)
	List(ctx context.Context, filters ListFilters) ([]*Market, error)
	ListByStatus(ctx context.Context, status string, p Page) ([]*Market, error)
	Search(ctx context.Context, query string, filters SearchFilters) ([]*Market, error)
	GetPublicMarket(ctx context.Context, marketID int64) (*PublicMarket, error)
}

// MarketWriteRepository exposes market writes and maintenance operations.
type MarketWriteRepository interface {
	Create(ctx context.Context, market *Market) error
	UpdateLabels(ctx context.Context, id int64, yesLabel, noLabel string) error
	Delete(ctx context.Context, id int64) error
	ResolveMarket(ctx context.Context, id int64, resolution string) error
}

// MarketPositionRepository exposes position-related queries.
type MarketPositionRepository interface {
	GetUserPosition(ctx context.Context, marketID int64, username string) (*UserPosition, error)
	ListMarketPositions(ctx context.Context, marketID int64) (MarketPositions, error)
	CalculatePayoutPositions(ctx context.Context, marketID int64) ([]*PayoutPosition, error)
}

// MarketBetRepository exposes bet history queries.
type MarketBetRepository interface {
	ListBetsForMarket(ctx context.Context, marketID int64) ([]*Bet, error)
}

// Repository defines the interface for market data access.
type Repository interface {
	MarketReadRepository
	MarketWriteRepository
	MarketPositionRepository
	MarketBetRepository
}

// CreatorSummary captures lightweight information about a market creator.
type CreatorSummary struct {
	Username      string
	DisplayName   string
	PersonalEmoji string
}

// ProbabilityPoint records a market probability at a specific moment.
type ProbabilityPoint struct {
	Probability float64
	Timestamp   time.Time
}

// UserService defines the interface for user-related operations.
type UserService interface {
	ValidateUserExists(ctx context.Context, username string) error
	ValidateUserBalance(ctx context.Context, username string, requiredAmount int64, maxDebt int64) error
	DeductBalance(ctx context.Context, username string, amount int64) error
	ApplyTransaction(ctx context.Context, username string, amount int64, transactionType string) error
	GetPublicUser(ctx context.Context, username string) (*users.PublicUser, error)
}

// Config holds configuration for the markets service.
type Config struct {
	MinimumFutureHours float64
	CreateMarketCost   int64
	MaximumDebtAllowed int64
}

// CreationPolicy governs validation and construction of markets.
type CreationPolicy interface {
	ValidateCreateRequest(req MarketCreateRequest) error
	ValidateCustomLabels(yesLabel, noLabel string) error
	NormalizeLabels(yesLabel, noLabel string) labelPair
	ValidateResolutionTime(now time.Time, resolution time.Time, minimumFutureHours float64) error
	EnsureCreateMarketBalance(ctx context.Context, users UserService, creatorUsername string, cost int64, maxDebt int64) error
	BuildMarketEntity(now time.Time, req MarketCreateRequest, creatorUsername string, labels labelPair) *Market
}

// ResolutionPolicy encapsulates resolution rules and post-resolution actions.
type ResolutionPolicy interface {
	NormalizeResolution(resolution string) (string, error)
	ValidateResolutionRequest(market *Market, username string) error
	Resolve(ctx context.Context, repo ResolutionRepository, userService UserService, marketID int64, outcome string) error
}

// ProbabilityChange represents a change in market probability at a timestamp.
type ProbabilityChange struct {
	Probability float64
	Timestamp   time.Time
}

// ProbabilityEngine provides probability calculations and projections.
type ProbabilityEngine interface {
	Calculate(createdAt time.Time, bets []models.Bet) []ProbabilityChange
	Project(createdAt time.Time, bets []models.Bet, newBet models.Bet) ProbabilityProjection
}

// ProbabilityValidator validates projection requests and market eligibility.
type ProbabilityValidator interface {
	ValidateRequest(req ProbabilityProjectionRequest) error
	ValidateMarket(market *Market, now time.Time) error
}

// SearchPolicy encapsulates search query validation and fallback logic.
type SearchPolicy interface {
	ValidateQuery(query string) error
	NormalizeFilters(filters SearchFilters) SearchFilters
	ShouldFetchFallback(primary []*Market, status string) bool
	NewSearchResults(query string, status string, primary []*Market) *SearchResults
	BuildFallbackFilters(primary SearchFilters) SearchFilters
	SelectFallback(primary []*Market, all []*Market, limit int) []*Market
}

// MetricsCalculator computes volume and dust metrics.
type MetricsCalculator interface {
	Volume(bets []models.Bet) int64
	VolumeWithDust(bets []models.Bet) int64
	Dust(bets []models.Bet) int64
}

// LeaderboardCalculator computes leaderboard standings.
type LeaderboardCalculator interface {
	Calculate(snapshot positionsmath.MarketSnapshot, bets []models.Bet) ([]positionsmath.UserProfitability, error)
}

// StatusPolicy validates status filters and pagination rules.
type StatusPolicy interface {
	ValidateStatus(status string) error
	NormalizePage(p Page, defaultLimit, maxLimit int) Page
}

// ListFilters represents filters for listing markets.
type ListFilters struct {
	Status    string
	CreatedBy string
	Limit     int
	Offset    int
}

// SearchFilters represents filters for searching markets.
type SearchFilters struct {
	Status string
	Limit  int
	Offset int
}

// SearchResults represents the result of a market search with fallback.
type SearchResults struct {
	PrimaryResults  []*Market `json:"primaryResults"`
	FallbackResults []*Market `json:"fallbackResults"`
	Query           string    `json:"query"`
	PrimaryStatus   string    `json:"primaryStatus"`
	PrimaryCount    int       `json:"primaryCount"`
	FallbackCount   int       `json:"fallbackCount"`
	TotalCount      int       `json:"totalCount"`
	FallbackUsed    bool      `json:"fallbackUsed"`
}

// ServiceInterface defines the interface for market service operations.
type ServiceInterface interface {
	CreateMarket(ctx context.Context, req MarketCreateRequest, creatorUsername string) (*Market, error)
	SetCustomLabels(ctx context.Context, marketID int64, yesLabel, noLabel string) error
	GetMarket(ctx context.Context, id int64) (*Market, error)
	ListMarkets(ctx context.Context, filters ListFilters) ([]*Market, error)
	SearchMarkets(ctx context.Context, query string, filters SearchFilters) (*SearchResults, error)
	ResolveMarket(ctx context.Context, marketID int64, resolution string, username string) error
	ListByStatus(ctx context.Context, status string, p Page) ([]*Market, error)
	GetMarketLeaderboard(ctx context.Context, marketID int64, p Page) ([]*LeaderboardRow, error)
	ProjectProbability(ctx context.Context, req ProbabilityProjectionRequest) (*ProbabilityProjection, error)
	GetMarketDetails(ctx context.Context, marketID int64) (*MarketOverview, error)
	GetMarketBets(ctx context.Context, marketID int64) ([]*BetDisplayInfo, error)
	GetMarketPositions(ctx context.Context, marketID int64) (MarketPositions, error)
	GetUserPositionInMarket(ctx context.Context, marketID int64, username string) (*UserPosition, error)
	CalculateMarketVolume(ctx context.Context, marketID int64) (int64, error)
	GetPublicMarket(ctx context.Context, marketID int64) (*PublicMarket, error)
}

// Service implements the core market business logic.
type Service struct {
	repo        Repository
	userService UserService
	clock       Clock
	config      Config

	creationPolicy        CreationPolicy
	resolutionPolicy      ResolutionPolicy
	probabilityEngine     ProbabilityEngine
	probabilityValidator  ProbabilityValidator
	searchPolicy          SearchPolicy
	metricsCalculator     MetricsCalculator
	leaderboardCalculator LeaderboardCalculator
	statusPolicy          StatusPolicy
}

// ServiceOption configures the markets service strategies.
type ServiceOption func(*Service)

// WithCreationPolicy overrides the market creation policy.
func WithCreationPolicy(p CreationPolicy) ServiceOption {
	return func(s *Service) {
		if p != nil {
			s.creationPolicy = p
		}
	}
}

// WithResolutionPolicy overrides the resolution policy.
func WithResolutionPolicy(p ResolutionPolicy) ServiceOption {
	return func(s *Service) {
		if p != nil {
			s.resolutionPolicy = p
		}
	}
}

package markets

import (
	"strings"
	"time"

	"socialpredict/models"
)

type modelBetAssembler interface {
	Assemble() models.Bet
}

type publicMarketAssembler interface {
	Assemble() *PublicMarket
}

// Market represents the core market domain model
type Market struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	ResolutionResult        string
	CreatorUsername         string
	YesLabel                string
	NoLabel                 string
	Status                  string
	CreatedAt               time.Time
	UpdatedAt               time.Time
	InitialProbability      float64
	UTCOffset               int
}

// CreatedBy reports whether the market belongs to the supplied creator username.
func (m *Market) CreatedBy(username string) bool {
	if m == nil {
		return false
	}
	return strings.TrimSpace(m.CreatorUsername) == strings.TrimSpace(username)
}

// IsResolved reports whether the market is in the resolved state.
func (m *Market) IsResolved() bool {
	if m == nil {
		return false
	}
	return strings.EqualFold(strings.TrimSpace(m.Status), "resolved")
}

// MarketCreateRequest represents the request to create a new market
type MarketCreateRequest struct {
	QuestionTitle      string
	Description        string
	OutcomeType        string
	ResolutionDateTime time.Time
	YesLabel           string
	NoLabel            string
}

// HasCustomLabels reports whether the create request includes either custom label.
func (r MarketCreateRequest) HasCustomLabels() bool {
	return strings.TrimSpace(r.YesLabel) != "" || strings.TrimSpace(r.NoLabel) != ""
}

// UserPosition represents a user's holdings within a market.
type UserPosition struct {
	Username         string
	MarketID         int64
	YesSharesOwned   int64
	NoSharesOwned    int64
	Value            int64
	TotalSpent       int64
	TotalSpentInPlay int64
	IsResolved       bool
	ResolutionResult string
}

// MarketPositions aggregates user positions for a market.
type MarketPositions []*UserPosition

// Normalize returns a non-nil collection for callers that treat empty and nil identically.
func (p MarketPositions) Normalize() MarketPositions {
	if p == nil {
		return MarketPositions{}
	}
	return p
}

// Bet represents a wager placed within a market.
type Bet struct {
	ID        uint
	Username  string
	MarketID  uint
	Amount    int64
	Outcome   string
	PlacedAt  time.Time
	CreatedAt time.Time
}

type domainBetAssembler struct {
	bet *Bet
}

func (a domainBetAssembler) Assemble() models.Bet {
	if a.bet == nil {
		return models.Bet{}
	}

	return models.Bet{
		Username: a.bet.Username,
		MarketID: a.bet.MarketID,
		Amount:   a.bet.Amount,
		Outcome:  a.bet.Outcome,
		PlacedAt: a.bet.PlacedAt,
	}
}

// ToModelBet converts the domain bet into the shared model shape used by math services.
func (b Bet) ToModelBet() models.Bet {
	return domainBetAssembler{bet: &b}.Assemble()
}

// ToModelBets converts a domain bet slice into the shared model representation.
func ToModelBets(bets []*Bet) []models.Bet {
	if len(bets) == 0 {
		return []models.Bet{}
	}

	modelBets := make([]models.Bet, len(bets))
	for i, bet := range bets {
		modelBets[i] = domainBetAssembler{bet: bet}.Assemble()
	}

	return modelBets
}

// PayoutPosition captures the resolved valuation per user for distribution.
type PayoutPosition struct {
	Username string
	Value    int64
}

// IsPayable reports whether the payout position results in a positive transfer.
func (p *PayoutPosition) IsPayable() bool {
	return p != nil && p.Value > 0
}

// PublicMarket represents the public view of a market.
type PublicMarket struct {
	ID                      int64
	QuestionTitle           string
	Description             string
	OutcomeType             string
	ResolutionDateTime      time.Time
	FinalResolutionDateTime time.Time
	UTCOffset               int
	IsResolved              bool
	ResolutionResult        string
	InitialProbability      float64
	CreatorUsername         string
	CreatedAt               time.Time
	YesLabel                string
	NoLabel                 string
}

// Resolved reports whether the public market already has a terminal resolution.
func (m *PublicMarket) Resolved() bool {
	return m != nil && m.IsResolved
}

type marketPublicAssembler struct {
	target *PublicMarket
	market *Market
}

func (a marketPublicAssembler) Assemble() *PublicMarket {
	if a.market == nil {
		return nil
	}

	target := a.target
	if target == nil {
		target = &PublicMarket{}
	}

	*target = PublicMarket{
		ID:                      a.market.ID,
		QuestionTitle:           a.market.QuestionTitle,
		Description:             a.market.Description,
		OutcomeType:             a.market.OutcomeType,
		ResolutionDateTime:      a.market.ResolutionDateTime,
		FinalResolutionDateTime: a.market.FinalResolutionDateTime,
		UTCOffset:               a.market.UTCOffset,
		IsResolved:              a.market.IsResolved(),
		ResolutionResult:        a.market.ResolutionResult,
		InitialProbability:      a.market.InitialProbability,
		CreatorUsername:         a.market.CreatorUsername,
		CreatedAt:               a.market.CreatedAt,
		YesLabel:                a.market.YesLabel,
		NoLabel:                 a.market.NoLabel,
	}

	return target
}

// FromMarket copies the public fields from a domain market into the public view model.
func (m *PublicMarket) FromMarket(market *Market) *PublicMarket {
	return marketPublicAssembler{target: m, market: market}.Assemble()
}

package markets

import "errors"

// MarketError exposes message-based sentinel errors behind a reusable type.
type MarketError interface {
	error
	Message() string
}

type staticMarketError struct {
	message string
}

func (e staticMarketError) Error() string   { return e.message }
func (e staticMarketError) Message() string { return e.message }

type marketErrorFactory interface {
	New(message string) MarketError
}

type staticMarketErrorFactory struct{}

func (staticMarketErrorFactory) New(message string) MarketError {
	return staticMarketError{message: message}
}

func newDomainError(message string) error {
	return staticMarketErrorFactory{}.New(message)
}

var (
	// ErrMarketNotFound indicates that the requested market does not exist.
	ErrMarketNotFound = newDomainError("market not found")
	// ErrInvalidQuestionTitle indicates that the market question title is invalid.
	ErrInvalidQuestionTitle = newDomainError("invalid question title")
	// ErrInvalidQuestionLength indicates that the market question title is blank or too long.
	ErrInvalidQuestionLength = newDomainError("question title exceeds maximum length or is blank")
	// ErrInvalidDescriptionLength indicates that the market description is too long.
	ErrInvalidDescriptionLength = newDomainError("question description exceeds maximum length")
	// ErrInvalidLabel indicates that one or more custom labels are invalid.
	ErrInvalidLabel = newDomainError("invalid label")
	// ErrInvalidResolutionTime indicates that the supplied resolution time is invalid.
	ErrInvalidResolutionTime = newDomainError("invalid market resolution time")
	// ErrUserNotFound indicates that the referenced creator user does not exist.
	ErrUserNotFound = newDomainError("creator user not found")
	// ErrInsufficientBalance indicates that the actor does not have enough balance.
	ErrInsufficientBalance = newDomainError("insufficient balance")
	// ErrUnauthorized indicates that the actor is not allowed to perform the action.
	ErrUnauthorized = newDomainError("unauthorized")
	// ErrInvalidInput indicates that one or more request inputs are invalid.
	ErrInvalidInput = newDomainError("invalid input")
	// ErrInvalidState indicates that the market state does not allow the requested action.
	ErrInvalidState = newDomainError("invalid state")
)

// IsMarketNotFound reports whether err represents a missing market.
func IsMarketNotFound(err error) bool {
	return errors.Is(err, ErrMarketNotFound)
}

// IsInvalidInput reports whether err represents invalid caller input.
func IsInvalidInput(err error) bool {
	return errors.Is(err, ErrInvalidInput)
}

// IsUnauthorized reports whether err represents an authorization failure.
func IsUnauthorized(err error) bool {
	return errors.Is(err, ErrUnauthorized)
}

// IsInvalidState reports whether err represents an invalid market state transition.
func IsInvalidState(err error) bool {
	return errors.Is(err, ErrInvalidState)
}

// WithProbabilityEngine overrides the probability engine.
func WithProbabilityEngine(e ProbabilityEngine) ServiceOption {
	return func(s *Service) {
		if e != nil {
			s.probabilityEngine = e
		}
	}
}

// WithProbabilityValidator overrides the probability validator.
func WithProbabilityValidator(v ProbabilityValidator) ServiceOption {
	return func(s *Service) {
		if v != nil {
			s.probabilityValidator = v
		}
	}
}

// WithSearchPolicy overrides the search policy.
func WithSearchPolicy(p SearchPolicy) ServiceOption {
	return func(s *Service) {
		if p != nil {
			s.searchPolicy = p
		}
	}
}

// WithMetricsCalculator overrides the metrics calculator.
func WithMetricsCalculator(c MetricsCalculator) ServiceOption {
	return func(s *Service) {
		if c != nil {
			s.metricsCalculator = c
		}
	}
}

// WithLeaderboardCalculator overrides the leaderboard calculator.
func WithLeaderboardCalculator(c LeaderboardCalculator) ServiceOption {
	return func(s *Service) {
		if c != nil {
			s.leaderboardCalculator = c
		}
	}
}

// WithStatusPolicy overrides the status policy.
func WithStatusPolicy(p StatusPolicy) ServiceOption {
	return func(s *Service) {
		if p != nil {
			s.statusPolicy = p
		}
	}
}

// WithClock overrides the clock used by the service.
func WithClock(clock Clock) ServiceOption {
	return func(s *Service) {
		if clock != nil {
			s.clock = clock
		}
	}
}

// NewService creates a new markets service.
func NewService(repo Repository, userService UserService, clock Clock, config Config, opts ...ServiceOption) *Service {
	s := &Service{
		repo:        repo,
		userService: userService,
		clock:       clock,
		config:      config,
	}

	for _, opt := range opts {
		opt(s)
	}

	s.ensureDefaults()

	return s
}

func (s *Service) ensureDefaults() {
	if s.clock == nil {
		s.clock = serviceClock{}
	}
	if s.creationPolicy == nil {
		s.creationPolicy = defaultCreationPolicy{config: s.config}
	}
	if s.resolutionPolicy == nil {
		s.resolutionPolicy = defaultResolutionPolicy{}
	}
	if s.probabilityEngine == nil {
		s.probabilityEngine = defaultProbabilityEngine{}
	}
	if s.probabilityValidator == nil {
		s.probabilityValidator = defaultProbabilityValidator{}
	}
	if s.searchPolicy == nil {
		s.searchPolicy = defaultSearchPolicy{}
	}
	if s.metricsCalculator == nil {
		s.metricsCalculator = defaultMetricsCalculator{}
	}
	if s.leaderboardCalculator == nil {
		s.leaderboardCalculator = defaultLeaderboardCalculator{}
	}
	if s.statusPolicy == nil {
		s.statusPolicy = defaultStatusPolicy{}
	}
}

var (
	_ ServiceInterface = (*Service)(nil)
	_ Clock            = serviceClock{}
)

